VALUES
  ('aboriginal-f0899a01-moex-00637', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '有關訴願之敘述，下列何者正確？ 原處分機關認為訴願有理由者，應自行撤銷原處分，毋須通知訴願管轄機關 原處分機關認為訴願有理由者，自行撤銷原處分後，訴願管轄機關應為訴願駁回之決定 訴願人誤向訴願管轄機關以外之機關提起訴願者，該機關應為訴願不受理之決定 受理訴願機關認為有必要時，得依職權通知訴願人及原處分機關進行言詞辯論', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00638', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依訴願法第77條規定，下列何者非屬不受理決定之事由？ 提起訴願逾法定期間    行政處分已不存在 對已撤回之訴願事件重行提起訴願  為決定基礎之證物，係偽造或變造', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00639', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依訴願法規定，關於訴願審議程序之敘述，下列何者錯誤？ 場陳述意見 日未完備者，得再為辯論', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00640', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '甲、乙公同共有之土地被徵收，甲針對徵收處分提起撤銷之訴，有關訴訟中乙參加訴訟之敘述，下列 何者錯誤？ 訴訟標的對於甲及乙必須合一確定 行政法院應以裁定命乙參加訴訟 乙之行為有利益於共同訴訟人者，其效力及於全體 乙對於命其參加之裁定得聲明不服', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00641', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '行政法院審查古蹟或歷史建築等文化資產審議決定時，關於判斷餘地之審查，下列敘述何者錯誤？ 法院得審查文化資產審議決定所憑藉的基礎事實是否正確 法院得審查審議程序是否符合正當行政程序及審議委員會之組織是否合法 法院得審查文化資產保存價值判斷之結論與相關學術領域多數見解是否相符 文資審議決定對當事人基本權之限制越重大，應採越高之審查密度', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00642', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '有關透過都市計畫審查程序，請求行政法院宣告都市計畫無效之制度，下列敘述何者正確？ 此類程序以都市計畫發布機關為被告 提起都市計畫審查訴訟前，不須經訴願程序 以都市計畫違法、不當導致直接損害或將損害原告權利或法律上利益為實體裁判要件 為維護法安定性，都市計畫審查訴訟一律於都市計畫發布後1年內之不變期間內提起', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00643', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '甲機關進行土地開發環境影響評估決定後，該決定經最高行政法院判決撤銷確定，關於確定判決效力 之敘述，下列何者正確？ 確定判決有拘束甲機關效力  本於權力分立，甲機關對判決可置之不理 甲機關仍得以原評估決定之理由重為處分  甲機關得另行發布解釋函令，並據以維持原評估決定', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 45, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00644', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依據行政訴訟法之規定，原告之訴該當於下列何者，行政法院不得以裁定逕予駁回？ 本案經終局判決後撤回其訴，復提起同一訴訟  起訴逾越法定期間 原告就已起訴之事件，於訴訟繫屬中更行起訴  原告之訴，依其所訴事實在法律上顯無理由', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 46, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00645', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於國家賠償法公共設施之國家賠償責任要件，下列敘述何者錯誤？ 國家必須對於該等設施之設置或管理有所欠缺 國家必須對於該等設施具有所有權 人民之損害與設施之設置管理欠缺必須有因果關係 公共設施委由民間團體管理，因管理欠缺而發生損害，國家應負損害賠償責任', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00646', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於土地徵收之敘述，下列何者錯誤？ 係以公權力剝奪人民之財產權  財產權人構成特別犧牲 得要求合理補償    得依據法規命令為徵收', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
